import { Router } from 'express';
import { getBooks, issueBook, returnBook, getLoans } from '../controllers/libraryController.js';
import { authenticateToken, authorizeRoles } from '../middleware/authMiddleware.js';
const router = Router();
router.use(authenticateToken);
router.get('/books', authorizeRoles('librarian', 'super-admin', 'school-admin'), getBooks);
router.post('/issue', authorizeRoles('librarian', 'super-admin'), issueBook);
router.post('/return/:loan_id', authorizeRoles('librarian', 'super-admin'), returnBook);
router.get('/loans', authorizeRoles('librarian', 'super-admin', 'school-admin'), getLoans);
export default router;
